package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecord_DefaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set skipHeaderRecord to false for testing if needed
        setSkipHeaderRecord(format, false);
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        // Use reflection to confirm the field is true
        setSkipHeaderRecord(format, true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecord_CustomFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        // Use reflection to confirm the field is false
        setSkipHeaderRecord(format, false);
        assertFalse(format.getSkipHeaderRecord());
    }

    private void setSkipHeaderRecord(CSVFormat format, boolean value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        field.setAccessible(true);
        field.set(format, value);
    }
}
